function validateRouteParameter(req, res, next) {
    var routeParameter = req.params.routeParameter;
    var regex = /^\d+$/;
    if (regex.test(routeParameter)) {
        res.status(200).send('OK');
    } else {
        res.status(400).send('Bad Request');
    }
    next();
}

